content.query:
let p_DetectionId = tostring("{DetectionId}");
let p_EntityId    = tostring("{EntityId}");
let DetectionFilterActive = p_DetectionId !in ("", "<unset>", "null");
let EntityFilterActive    = p_EntityId    !in ("", "<unset>", "null");
let AnyFilterActive = DetectionFilterActive or EntityFilterActive;
let EntityName = toscalar(
    union isfuzzy=true VectraDetectionsCombined
    | where TimeGenerated > ago(90d)
    | extend det_id = replace_regex(tostring(column_ifexists("detection_id", column_ifexists("Detection ID", ""))), @"\.0$", "")
    | extend eid    = replace_regex(tostring(column_ifexists("entity_id",    column_ifexists("Entity ID",    ""))), @"\.0$", "")
    | extend ename  = tostring(column_ifexists("entity_name", column_ifexists("Entity Name", "")))
    | where (DetectionFilterActive and det_id == p_DetectionId)
         or (EntityFilterActive    and eid    == p_EntityId)
    | top 1 by TimeGenerated desc
    | project ename
);
SecurityIncident
| where AnyFilterActive and isnotempty(EntityName)
| where Title contains EntityName
| summarize arg_max(TimeGenerated, *) by IncidentNumber
| project IncidentNumber, Title, Status,
    Owner = tostring(Owner), CreatedTime, LastActivityTime,
    XDRIncidentId = tostring(ProviderIncidentId),
    IncidentUrl = tostring(IncidentUrl)
| order by LastActivityTime desc
